boolean hasCycle(ListNode head) {
  ListNode slow = head, fast = head;
  while (fast != null && fast.next != null) {
    slow = slow.next;
    fast = fast.next.next;
    if (slow == fast) return true;
  }
  return false;
}

ListNode reverse(ListNode head) {
  ListNode prev = null, curr = head;
  while (curr != null) {
    ListNode next = curr.next;
    curr.next = prev;
    prev = curr;
    curr = next;
  }
  return prev;
}

public ListNode reverseList(ListNode head) {
  ListNode prev = null;
  ListNode curr = head;
  while (curr != null) {
    ListNode nextNode = curr.next;
    curr.next = prev;
    prev = curr;
    curr = nextNode;
  }
  return prev;
}

// Iterative Inorder
List<Integer> inorder(TreeNode root) {
  List<Integer> res = new ArrayList<>();
  Deque<TreeNode> stack = new ArrayDeque<>();
  TreeNode curr = root;
  while (curr != null || !stack.isEmpty()) {
    while (curr != null) { stack.push(curr); curr = curr.left; }
    curr = stack.pop();
    res.add(curr.val);
    curr = curr.right;
  }
  return res;
}

TreeNode deleteNode(TreeNode root, int key) {
  if (root == null) return null;
  if (key < root.val) root.left = deleteNode(root.left, key);
  else if (key > root.val) root.right = deleteNode(root.right, key);
  else {
    if (root.left == null) return root.right;
    if (root.right == null) return root.left;
    TreeNode succ = root.right;
    while (succ.left != null) succ = succ.left;
    root.val = succ.val;
    root.right = deleteNode(root.right, succ.val);
  }
  return root;
}

class NumArray {
  int[] tree;
  int n;
  public NumArray(int[] nums) {
    n = nums.length; tree = new int[n * 2];
    System.arraycopy(nums, 0, tree, n, n);
    for (int i = n - 1; i > 0; --i) tree[i] = tree[i * 2] + tree[i * 2 + 1];
  }
  public void update(int pos, int val) {
    for (tree[pos += n] = val; pos > 1; pos >>= 1)
      tree[pos >> 1] = tree[pos] + tree[pos ^ 1];
  }
  public int sumRange(int left, int right) {
    int sum = 0;
    for (left += n, right += n; left <= right; left >>= 1, right >>= 1) {
      if ((left & 1) == 1) sum += tree[left++];
      if ((right & 1) == 0) sum += tree[right--];
    }
    return sum;
  }
}

public TreeNode lowestCommonAncestor(TreeNode root, TreeNode p, TreeNode q) {
  if (root == null || root == p || root == q) return root;
  TreeNode left = lowestCommonAncestor(root.left, p, q);
  TreeNode right = lowestCommonAncestor(root.right, p, q);
  if (left != null && right != null) return root;
  return left != null ? left : right;
}

// K Largest Elements
int[] kLargest(int[] nums, int k) {
  PriorityQueue<Integer> minH = new PriorityQueue<>();
  for (int n : nums) {
    minH.offer(n);
    if (minH.size() > k) minH.poll();
  }
  return minH.stream().mapToInt(x->x).toArray();
}

public int findKthLargest(int[] nums, int k) {
  PriorityQueue<Integer> minHeap = new PriorityQueue<>();
  for (int num : nums) {
    minHeap.offer(num);
    if (minHeap.size() > k) {
      minHeap.poll();
    }
  }
  return minHeap.peek();
}

