// Subsets
void backtrack(List<List<Integer>> res, List<Integer> cur,
    int[] nums, int start) {
  res.add(new ArrayList<>(cur));
  for (int i = start; i < nums.length; i++) {
    cur.add(nums[i]);            // choose
    backtrack(res, cur, nums, i+1); // explore
    cur.remove(cur.size()-1);  // unchoose
  }
}

// Activity Selection / Interval Scheduling
int maxActivities(int[][] intervals) {
  Arrays.sort(intervals, (a,b)->a[1]-b[1]); // sort by end
  int count = 1, end = intervals[0][1];
  for (int i = 1; i < intervals.length; i++)
    if (intervals[i][0] >= end) { count++; end = intervals[i][1]; }
  return count;
}

public int pow(int x, int n) {
  if (n == 0) return 1;
  int half = pow(x, n / 2);
  if (n % 2 == 0) return half * half;
  else return half * half * x;
}
